/* =================================================================
   SHAPE_AUTOFIT — per-shape target diameter inside the cueball.
   Aspect glyphs traced by tools/trace_symbol.py are normalized to the
   full 320×320 viewBox, which leaves them crowded against the rim.
   Autofit re-centers the shape's bbox on (160,160) and scales it to
   fit inside this diameter, so glyphs sit like a sigil painted in the
   ball instead of stretching to its edge. Procedural shapes (default-
   ring, vriska-eye) are authored for the full viewBox and skip this.
   ================================================================= */
const SCRYBALL_SHAPE_AUTOFIT = {
  'light':  { diameter: SCRYBALL_AUTOFIT_DIAMETER, dx: 3, dy: 0 },
  'time':   { diameter: SCRYBALL_AUTOFIT_DIAMETER, dx: -1, dy: 0 },
  'mind':   { diameter: SCRYBALL_AUTOFIT_DIAMETER, dx: 5, dy: -8 },
  'heart':  SCRYBALL_AUTOFIT_DIAMETER,
  'void':   SCRYBALL_AUTOFIT_DIAMETER,
  'breath': SCRYBALL_AUTOFIT_DIAMETER,
  'blood':  SCRYBALL_AUTOFIT_DIAMETER,
  'space':  SCRYBALL_AUTOFIT_DIAMETER,
  'hope':   SCRYBALL_AUTOFIT_DIAMETER,
  'rage':   SCRYBALL_AUTOFIT_DIAMETER,
  'life':   SCRYBALL_AUTOFIT_DIAMETER,
  'doom':   SCRYBALL_AUTOFIT_DIAMETER,
  'sburb':  SCRYBALL_AUTOFIT_DIAMETER,
};

/* =================================================================
   Choreography timing (ms) — kept identical to the original mockup
   so the visual rhythm is preserved through componentization.
   ================================================================= */
const SCRYBALL_BEATS = [
  { at:    0, cls: 'scrolling' },
  { at:  700, cls: 'stamping'  },
  { at: 1900, cls: 'flashing'  },
  { at: 2400, cls: 'opening'   },
  { at: 3000, cls: 'diving'    },
  { at: 3850, cls: 'arriving'  },
  { at: 4600, cls: 'inside',   final: true },
];
const SCRYBALL_BEAT_NAMES = SCRYBALL_BEATS.map(b => b.cls);

const SCRYBALL_SVG_NS = 'http://www.w3.org/2000/svg';

/* =========================================================================
   ScryingBall — the React component
   ========================================================================= */
const ScryingBall = ({
  playToken = 0,
  resetToken = 0,
  shape = 'default-ring',
  n = 0,
  flashColor = '#e50000',
  onArrived,
}) => {
  const cutoutsRef   = useRef(null);
  const interiorsRef = useRef(null);
  const outlinesRef  = useRef(null);
  const ballWrapRef  = useRef(null);
  const animatingRef = useRef(false);
  const timersRef    = useRef([]);
  const initialPlayRef = useRef(playToken);
  const initialResetRef = useRef(resetToken);

  // ----- Render cutouts whenever shape/n changes ------------------------
  useEffect(() => {
    renderCutoutsImperative(shape, n);
  }, [shape, n]);

  // ----- Flash color → CSS variable -------------------------------------
  useEffect(() => {
    if (ballWrapRef.current) {
      ballWrapRef.current.style.setProperty('--flash-color', flashColor || '#e50000');
    }
  }, [flashColor]);

  // ----- Play animation when playToken increments -----------------------
  useEffect(() => {
    // Skip the initial render so the ball doesn't auto-play on mount.
    if (playToken === initialPlayRef.current) return;
    runDive();
  }, [playToken]);

  // ----- Reset when resetToken increments -------------------------------
  useEffect(() => {
    if (resetToken === initialResetRef.current) return;
    hardReset();
  }, [resetToken]);

  // ----- Cleanup on unmount ---------------------------------------------
  useEffect(() => () => {
    timersRef.current.forEach(clearTimeout);
    hardReset();
  }, []);

  // ----- Imperative helpers (closures over refs) ------------------------

  function renderCutoutsImperative(shapeKey, count) {
    const cutoutsEl   = cutoutsRef.current;
    const interiorsEl = interiorsRef.current;
    const outlinesEl  = outlinesRef.current;
    if (!cutoutsEl || !interiorsEl || !outlinesEl) return;

    const build = SCRYBALL_CUTOUT_SHAPES[shapeKey] || SCRYBALL_CUTOUT_SHAPES['default-ring'];
    const parts = build(count);
    cutoutsEl.innerHTML   = '';
    interiorsEl.innerHTML = '';
    outlinesEl.innerHTML  = '';

    parts.forEach(({ d }) => {
      // Mask hole — black inside white mask = ball transparent there.
      const mp = document.createElementNS(SCRYBALL_SVG_NS, 'path');
      mp.setAttribute('d', d);
      mp.setAttribute('fill', 'black');
      cutoutsEl.appendChild(mp);

      // Flash interior — filled with the aspect color via CSS var.
      const ip = document.createElementNS(SCRYBALL_SVG_NS, 'path');
      ip.setAttribute('class', 'cutout-interior');
      ip.setAttribute('d', d);
      interiorsEl.appendChild(ip);

      // Etched outline — stroked + dasharray-animated.
      const op = document.createElementNS(SCRYBALL_SVG_NS, 'path');
      op.setAttribute('class', 'cutout-outline');
      op.setAttribute('d', d);
      op.setAttribute('pathLength', '100');
      outlinesEl.appendChild(op);
    });

    applyAutofit(shapeKey);
  }

  // Re-center + scale the rendered shape so it fits AUTOFIT_DIAMETER.
  function applyAutofit(shapeKey) {
    const cutoutsEl   = cutoutsRef.current;
    const interiorsEl = interiorsRef.current;
    const outlinesEl  = outlinesRef.current;
    if (!cutoutsEl || !interiorsEl || !outlinesEl) return;

    const cfg = SCRYBALL_SHAPE_AUTOFIT[shapeKey];
    if (!cfg) {
      cutoutsEl.removeAttribute('transform');
      interiorsEl.removeAttribute('transform');
      outlinesEl.removeAttribute('transform');
      return;
    }
    // Accept either a bare number (diameter only) or an object
    // {diameter, dx, dy} for per-shape visual-center fine-tuning.
    const target  = typeof cfg === 'number' ? cfg : cfg.diameter;
    const nudgeX  = typeof cfg === 'number' ? 0 : (cfg.dx || 0);
    const nudgeY  = typeof cfg === 'number' ? 0 : (cfg.dy || 0);

    let bbox;
    try { bbox = outlinesEl.getBBox(); } catch (e) { return; }
    if (!bbox || (bbox.width === 0 && bbox.height === 0)) return;

    const maxDim = Math.max(bbox.width, bbox.height);
    const scale  = target / maxDim;
    const cx     = bbox.x + bbox.width  / 2;
    const cy     = bbox.y + bbox.height / 2;
    const tx     = SCRYBALL_VCEN - cx * scale + nudgeX;
    const ty     = SCRYBALL_VCEN - cy * scale + nudgeY;
    const transform = `translate(${tx.toFixed(3)} ${ty.toFixed(3)}) scale(${scale.toFixed(4)})`;
    cutoutsEl.setAttribute('transform',   transform);
    interiorsEl.setAttribute('transform', transform);
    outlinesEl.setAttribute('transform',  transform);
  }

  // Snap everything back to pre-animation state.
  function hardReset() {
    timersRef.current.forEach(clearTimeout);
    timersRef.current = [];
    animatingRef.current = false;
    const body = document.body;
    SCRYBALL_BEAT_NAMES.forEach(c => body.classList.remove(c));
    // Legacy class names from earlier prototype passes — harmless if absent.
    body.classList.remove('summoning', 'revealing');
  }

  // Run the dive choreography. Re-renders cutouts first (in case the
  // shape/n props changed since the last render) so the etch+flash use
  // the most up-to-date silhouette.
  function runDive() {
    if (animatingRef.current) return;
    animatingRef.current = true;

    renderCutoutsImperative(shape, n);

    const body = document.body;
    hardReset();
    animatingRef.current = true;  // hardReset cleared this — set again

    // Wait two frames so the browser registers the cleared classes before
    // the new ones land; otherwise CSS transitions can be skipped.
    requestAnimationFrame(() => requestAnimationFrame(() => {
      SCRYBALL_BEATS.forEach(({ at, cls, final }) => {
        timersRef.current.push(setTimeout(() => {
          if (final) {
            // The 'inside' beat: clear all the intermediate beats so any
            // active animations don't keep ticking.
            SCRYBALL_BEAT_NAMES.filter(c => c !== 'inside')
              .forEach(c => body.classList.remove(c));
          }
          body.classList.add(cls);
          if (final) {
            animatingRef.current = false;
            if (typeof onArrived === 'function') onArrived();
          }
        }, at));
      });
    }));
  }

  // ----- Render -----------------------------------------------------------
  return (
    <div className="ball-stage">
      <div className="ball-wrap" ref={ballWrapRef}>
        {/* Behind-ball: dark scrying-space gradient + the in-ball blue
            pentagon that blooms through the cutouts at `opening`. */}
        <div className="ball-behind" aria-hidden="true">
          <svg className="ball-pentagon"
               viewBox="0 0 320 320"
               preserveAspectRatio="xMidYMid meet">
            <polygon className="ball-pentagon-poly"
                     points="160,215 212,177 192,116 128,116 108,177"/>
          </svg>
        </div>

        {/* Cueball SVG — mask + cutout/interior/outline groups, each
            populated imperatively by renderCutoutsImperative(). */}
        <svg className="cueball-svg"
             viewBox="0 0 320 320"
             preserveAspectRatio="xMidYMid meet"
             aria-hidden="true">
          <defs>
            <radialGradient id="scryballGrad" cx="36%" cy="30%" r="80%">
              <stop offset="0%"   stopColor="#ffffff"/>
              <stop offset="14%"  stopColor="#f5f5f5"/>
              <stop offset="46%"  stopColor="#d0d0d0"/>
              <stop offset="78%"  stopColor="#8a8a8a"/>
              <stop offset="100%" stopColor="#3a3a3a"/>
            </radialGradient>
            <mask id="scryballMask" maskUnits="userSpaceOnUse" x="0" y="0" width="320" height="320">
              <rect width="320" height="320" fill="white"/>
              <g className="cutouts" ref={cutoutsRef} fill="black" fillRule="evenodd"/>
            </mask>
          </defs>
          <g mask="url(#scryballMask)">
            <circle cx="160" cy="160" r="158" fill="url(#scryballGrad)"/>
            <ellipse cx="173" cy="98" rx="38" ry="29" fill="white" opacity="0.55"/>
            <circle cx="206" cy="148" r="7" fill="white" opacity="0.85"/>
            <circle cx="160" cy="160" r="157" fill="none" stroke="#000" strokeWidth="3" opacity="0.25"/>
          </g>
          <g className="cutout-interiors" ref={interiorsRef}/>
          <g className="cutout-outlines"  ref={outlinesRef}/>
        </svg>
      </div>
    </div>
  );
};

/* =========================================================================
   Globals — exposed so non-React consumers / dev tooling can use this stuff
   ========================================================================= */
window.ScryingBall        = ScryingBall;
window.ScryingBallShapes  = SCRYBALL_CUTOUT_SHAPES;
window.ScryingBallAutofit = SCRYBALL_SHAPE_AUTOFIT;
window.ScryingBallBeats   = SCRYBALL_BEATS;
